import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append(' ');
        }
        // Replace literal "\\n" sequences with spaces to handle escaped newlines in test data
        String processed = rawInput.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(processed);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            int[] a = new int[N];
            for (int i = 0; i < N; i++) {
                a[i] = Integer.parseInt(st.nextToken());
            }
            long cur = 0;
            for (int i = 0; i < K; i++) cur += a[i];
            long best = cur;
            for (int i = K; i < N; i++) {
                cur += a[i] - a[i - K];
                if (cur > best) best = cur;
            }
            sb.append(best);
            if (T > 0) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

